A hash map stores key-value pairs with O(1) average lookup via a hash function.
```javascript
// Count frequency O(n)
function frequency(arr) {
  const count = {};
  for (const x of arr) count[x] = (count[x] || 0) + 1;
  return count;
}

// Two-sum in O(n) using hash map
function twoSum(nums, target) {
  const seen = new Map();
  for (let i = 0; i < nums.length; i++) {
    const complement = target - nums[i];
    if (seen.has(complement)) return [seen.get(complement), i];
    seen.set(nums[i], i);
  }
  return [];
}
