// BFS: level-by-level, queue, finds shortest path
function bfs(g, start) {
  const visited = new Set([start]), queue = [start], result = [];
  while (queue.length) {
    const node = queue.shift();
    result.push(node);
    for (const n of g[node])
      if (!visited.has(n)) { visited.add(n); queue.push(n); }
  }
  return result;
}

// DFS: deep first, recursive, good for paths/cycles
function dfs(g, node, visited = new Set()) {
  visited.add(node);
  const result = [node];
  for (const n of g[node])
    if (!visited.has(n)) result.push(...dfs(g, n, visited));
  return result;
}
