<body>
<div class="app">
  <div class="header"><h1>My Todos</h1><p id="stats">0 tasks</p></div>
  <div class="input-row">
    <input id="in" placeholder="Add a task..." onkeydown="if(event.key==='Enter')addTodo()">
    <button onclick="addTodo()">+ Add</button>
  </div>
  <ul class="todo-list" id="list"></ul>
  <div class="footer"><span id="left"></span><button class="clear" onclick="clearDone()">Clear done</button></div>
</div>
<script>
let todos = JSON.parse(localStorage.getItem('todos') || '[]');
let nextId = Date.now();
const save = () => localStorage.setItem('todos', JSON.stringify(todos));
const esc = s => s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
function render() {
  document.getElementById('list').innerHTML = todos.map(t =>
    '<li class="todo-item' + (t.done?' done':'') + '" id="t'+t.id+'">' +
    '<input type="checkbox"'+(t.done?' checked':'')+' onchange="toggle('+t.id+')">' +
    '<span class="todo-text">'+esc(t.text)+'</span>' +
    '<button class="del" onclick="del('+t.id+')">&#x2715;</button></li>'
  ).join('');
  const active = todos.filter(t => !t.done).length;
  document.getElementById('stats').textContent = todos.length + ' task' + (todos.length!==1?'s':'');
  document.getElementById('left').textContent = active + ' remaining';
}
function addTodo() {
  const text = document.getElementById('in').value.trim();
  if (!text) return;
  todos.unshift({ id: nextId++, text, done: false });
  document.getElementById('in').value = '';
  save(); render();
}
function toggle(id) { const t = todos.find(t => t.id===id); if(t){t.done=!t.done;save();render();} }
function del(id) { todos = todos.filter(t => t.id!==id); save(); render(); }
function clearDone() { todos = todos.filter(t => !t.done); save(); render(); }
render();
</script>
